+    const error = `Agent '${agentId}' not found or provider not available`;
+    return { success: false, text: "", error };
+  }
+
+  const context: ProviderChatRequest["context"] = [];
+  let accumulatedText = "";
+  let turn = 0;
+
+  while (!abortController.signal.aborted) {
+    const providerRequest: ProviderChatRequest = {
+      message: turn === 0 ? request.message : "Continue after the tool result above.",
+      sessionId: request.sessionId,
+      requestId: request.requestId,
+      workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+      context: context.length ? context : undefined,
+    };
+    turn += 1;
+    let delegated = false;
+
+    try {
+      for await (const response of provider.executeChat(providerRequest, {
+        debugMode,
+        abortController,
+        temperature: agentConfig.config?.temperature,
+        maxTokens: agentConfig.config?.maxTokens,
+      })) {
+        if (response.type === "text") {
+          const text = response.content || "";
+          accumulatedText += text;
+          yield {
+            type: "claude_json",
+            data: { type: "assistant", content: text, model: response.metadata?.model },
+          };
+          continue;
+        }
+
+        const chatRoomMessage = createChatRoomMessage(response, agentId);
+        if (chatRoomMessage) {
+          yield {
+            type: "claude_json",
+            data: { type: "chat_room_message", message: chatRoomMessage, session_id: request.sessionId },
+          };
+        }
+
+        if (response.type === "error") {
+          const error = response.error || "Agent run failed";
+          if (!isDelegated) yield { type: "error", error };
+          return { success: false, text: accumulatedText, error };
+        }
+
+        if (response.type !== "tool_use" || response.toolName !== "delegate_task") continue;
+
+        const toolUseId = response.toolUseId || `delegate_task_${request.requestId}_${turn}`;
+        const delegate = parseDelegateTask(response.toolInput);
