+          streamError = `Circular delegation detected for agent '${delegate.agentId}'`;
+          result = { success: false, text: "", error: streamError };
+        } else if (!globalRegistry.getAgent(delegate.agentId) || !globalRegistry.getProviderForAgent(delegate.agentId)) {
+          streamError = `Agent '${delegate.agentId}' not found or provider not available`;
+          result = { success: false, text: "", error: streamError };
+        } else {
+          const delegatedRequest: ChatRequest = { ...request, message: delegate.instructions };
+          result = yield* executeAgentConversation(
+            delegate.agentId,
+            delegatedRequest,
+            abortController,
+            debugMode,
+            [...lineage, agentId],
+            true,
+          );
+        }
+
+        if (streamError) yield { type: "error", error: streamError };
+        const toolResult = {
+          type: "tool_result",
+          is_error: !result.success,
+          content: result.success ? (result.text || EMPTY_DELEGATE_RESULT) : (result.error || "Delegated agent run failed"),
+          tool_use_id: toolUseId,
+        };
+        yield toolResultStreamResponse(toolResult, request.sessionId);
+        context.push({ role: "user", content: JSON.stringify(toolResult) });
+        delegated = true;
+        break;
+      }
+    } catch (error) {
+      const message = error instanceof Error ? error.message : String(error);
+      if (!isDelegated) yield { type: "error", error: message };
+      return { success: false, text: accumulatedText, error: message };
+    }
+
+    if (!delegated) return { success: true, text: accumulatedText };
+  }
+
+  const error = "Request aborted";
+  if (!isDelegated) yield { type: "error", error };
+  return { success: false, text: accumulatedText, error };
